import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); 
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  // ESTADOS DE SEGURIDAD 2FA
  const [twoStep, setTwoStep] = useState(false); 
  const [otp, setOtp] = useState(''); 
  const [qrCode, setQrCode] = useState(''); 
  const [secret2FA, setSecret2FA] = useState('');

  const abortControllerRef = useRef(null);

  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error(error); } 
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        // ACTIVAMOS EL PASO 2 - BIOMÉTRICO/TOTP
        const setup = await axios.get('http://localhost:5000/api/2fa/setup');
        setQrCode(setup.data.qr);
        setSecret2FA(setup.data.secret);
        setUserRole(res.data.rol);
        setTwoStep(true); 
      }
    } catch (e) { alert("Datos incorrectos"); }
  };

  const verificar2FA = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/2fa/verify', { token: otp, secret: secret2FA });
      if (res.data.success) {
        setIsLoggedIn(true);
      } else {
        alert("Código de seguridad incorrecto");
      }
    } catch (e) { alert("Error en verificación"); }
  };

  const handleRegister = async () => {
    if (!usuario || !password || !email) return alert("Llena todos los campos incluyendo email");
    try {
      const res = await axios.post('http://localhost:5000/api/register', { 
       email, usuario, clave: password, rol: nuevoRol 
      });
      if (res.data.success) {
        alert("¡Cuenta creada!");
        setAuthMode('login');
      }
    } catch (e) { alert("Error al registrar"); }
  };

  const guardarProducto = async () => {
    try {
      await axios.post('http://localhost:5000/api/productos', {
        nombre: nuevoProd.nombre,
        stock: Number(nuevoProd.stock),
        precio_venta: Number(nuevoProd.precio_venta)
      });
      setShowForm(false);
      cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    } catch (e) { alert("Error al guardar"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Eliminar?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- VISTA LOGIN Y 2FA ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-8 rounded-[40px] shadow-2xl w-full max-sm border border-gray-700">

          {/* Pantalla de Segundo Paso (2FA) */}
          {twoStep ? (
            <div className="text-center animate-in zoom-in duration-300">
              <h2 className="text-2xl font-bold text-white mb-2 uppercase">Seguridad 2FA</h2>
              <p className="text-gray-400 text-xs mb-6 uppercase tracking-widest">Escanea con tu celular</p>

              <img src={qrCode} alt="QR Setup" className="mx-auto mb-6 rounded-3xl border-4 border-[#00c984] p-2 bg-white w-48" />

              <input 
                type="text" 
                maxLength="6"
                placeholder="000 000"
                className="w-full bg-[#444c56] text-white text-center text-4xl font-black py-4 rounded-3xl outline-none mb-6 tracking-[10px]"
                onChange={e => setOtp(e.target.value)}
              />

              <button 
                className="w-full bg-[#00c984] text-[#1e293b] font-black py-5 rounded-3xl text-xl hover:scale-105 transition"
                onClick={verificar2FA}
              >
                VERIFICAR ACCESO
              </button>
            </div>
          ) : (
            /* Pantalla de Login/Registro Normal */
            <div className="space-y-4">
              <div className="text-center mb-8">
                <h2 className="text-3xl font-bold text-white uppercase tracking-tighter">
                  {authMode === 'login' ? 'Mi Tiendita Pro' : 'Nuevo Usuario'}
                </h2>
                <div className="w-12 h-1 bg-[#00c984] mx-auto rounded-full mt-2"></div>
              </div>

              <input className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />

              {authMode === 'register' && (
                <>
                <input className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Email" onChange={e => setEmail(e.target.value)} />
                <select className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                  <option value="vendedor">Vendedor</option>
                  <option value="admin">Administrador</option>
                </select>
                </>
              )}

              <input type="password" title="Contraseña" className="w-full bg-[#444c56] text-white px-5 py-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />

              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-2xl hover:brightness-110 transition shadow-lg text-lg" 
                onClick={authMode === 'login' ? handleLogin : handleRegister}>
                {authMode === 'login' ? 'ENTRAR' : 'REGISTRAR'}
              </button>

              <p className="text-center text-[10px] text-gray-400 font-bold uppercase cursor-pointer pt-2" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                {authMode === 'login' ? '¿No tienes cuenta? Regístrate' : 'Ya tengo cuenta'}
              </p>
            </div>
          )}
        </div>
      </div>
    );
  }

  // --- VISTA DASHBOARD (Stats Gigantes) ---
  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {view === "dashboard" ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="bg-white p-10 border-2 border-gray-100 rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-gray-400 font-black uppercase mb-4 tracking-widest">Productos Totales</p>
              <p className="text-7xl font-black text-[#1e293b]">{stats.total_productos}</p>
            </div>
            <div className="bg-white p-10 border-2 border-gray-100 rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-red-400 font-black uppercase mb-4 tracking-widest">Bajo en Almacén</p>
              <p className="text-7xl font-black text-red-500">{stats.bajo_stock}</p>
            </div>
            <div className="bg-white p-10 border-2 border-gray-100 rounded-[50px] shadow-xl text-center">
              <p className="text-xs text-green-400 font-black uppercase mb-4 tracking-widest">Valor de Inventario</p>
              <p className="text-5xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
            </div>
          </div>
        ) : (
          /* VISTA INVENTARIO */
          <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h2 className="text-3xl font-black uppercase text-[#1e293b]">Gestión de Stock</h2>
                <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-8 py-4 rounded-3xl font-black text-sm uppercase transition hover:scale-105">
                    {showForm ? 'Cerrar' : '+ Agregar Producto'}
                </button>
            </div>
            {showForm && (
              <div className="bg-white p-8 rounded-[40px] border-4 border-dashed grid grid-cols-1 md:grid-cols-4 gap-4 animate-in slide-in-from-top duration-300">
                  <input className="p-4 bg-gray-100 rounded-2xl outline-none focus:ring-4 focus:ring-green-400/20" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                  <input className="p-4 bg-gray-100 rounded-2xl outline-none" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                  <input className="p-4 bg-gray-100 rounded-2xl outline-none" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                  <button onClick={guardarProducto} className="bg-[#00c984] text-[#1e293b] font-black rounded-2xl py-4 uppercase">Guardar en Base</button>
              </div>
            )}
            <div className="bg-white border rounded-[40px] shadow-2xl overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 text-xs font-black uppercase text-gray-400">
                      <tr><th className="p-6">Nombre</th><th className="p-6">Disponibilidad</th><th className="p-6">Precio Unitario</th><th className="p-6">Control</th></tr>
                  </thead>
                  <tbody className="divide-y text-md font-bold text-slate-700">
                      {productos.map(p => (
                      <tr key={p.id} className="hover:bg-green-50/50 transition duration-300">
                          <td className="p-6 uppercase">{p.nombre}</td>
                          <td className="p-6"><span className={`px-4 py-2 rounded-full text-xs font-black ${p.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>{p.stock} UNIDADES</span></td>
                          <td className="p-6 text-xl">${p.precio_venta}</td>
                          <td className="p-6"><button onClick={() => eliminar(p.id)} className="bg-red-50 text-red-400 p-4 rounded-2xl hover:bg-red-500 hover:text-white transition"><i className="fas fa-trash"></i></button></td>
                      </tr>
                      ))}
                  </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
